INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_001', '肺炎', 'Pneumonia', '["呼吸系统"]', '["犬", "猫"]', '肺部炎症反应，可由细菌、病毒、真菌或吸入性因素引起。犬最常见为细菌性肺炎，猫多为吸入性或病毒性。', '["细菌感染(博德特氏菌、链球菌)", "病毒感染", "真菌感染", "吸入性因素"]', '病原体入侵肺泡后炎症介质释放，中性粒细胞浸润，肺泡充满渗出液导致气体交换障碍和低氧血症。', '早期治疗预后良好。', 'intermediate', 3);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_002', '心力衰竭(犬)', 'CHF', '["心血管系统"]', '["犬"]', '心脏泵血功能不足以满足机体代谢需求，导致肺循环和/或体循环淤血。最常见病因是黏液样二尖瓣退化(MMVD)。', '["MMVD", "DCM", "先天性心脏病"]', '瓣膜关闭不全导致血液反流，心房压力升高导致肺静脉压升高引发肺水肿。', '取决于病因和控制程度。', 'advanced', 4);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_003', '猫哮喘', 'Feline Asthma', '["呼吸系统"]', '["猫"]', '猫下呼吸道慢性炎症性疾病，特征为气道高反应性和可逆性气流受限。', '["过敏原(尘螨、花粉、烟雾)", "环境刺激物", "应激", "特发性"]', 'IgE介导的I型超敏反应，肥大细胞脱颗粒，嗜酸性粒细胞浸润导致气道平滑肌收缩和黏膜水肿。', '需终身管理，多数猫经治疗可正常生活。', 'intermediate', 2);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_004', '气管塌陷', 'Tracheal Collapse', '["呼吸系统"]', '["犬"]', '气管软骨环变平、气管膜松弛导致气管腔狭窄，多见于小型犬。特征性表现为阵发性鹅叫样咳嗽。', '["遗传倾向(贵宾、约克夏)", "肥胖", "老年退行性变"]', '软骨结构异常导致吸气时气管塌陷气流受阻而咳嗽。', '控制症状为主，无法根治。', 'intermediate', 2);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_005', '急性肾损伤', 'AKI', '["泌尿系统", "急诊"]', '["犬", "猫"]', '肾功能急剧下降，表现为氮质血症、少尿/无尿和电解质紊乱。', '["缺血(脱水、休克)", "肾毒性药物(NSAIDs、乙二醇)", "钩端螺旋体病", "尿路梗阻"]', '肾血流下降或肾毒性因素导致肾小管上皮细胞坏死，GFR下降导致代谢废物蓄积。', '早期干预可逆，延误则可能进展为CKD或死亡。', 'advanced', 4);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_006', '慢性肾病', 'CKD', '["泌尿系统"]', '["犬", "猫"]', '肾功能进行性和不可逆性丧失，是老年猫最常见的疾病之一。', '["特发性肾小管间质性肾炎", "肾淀粉样变(猫)", "多囊肾(猫)", "既往AKI后遗症"]', '肾单位逐渐丢失，残余肾单位高滤过导致进一步损伤和纤维化。', '不可逆，但早期干预可显著延长生存期。', 'advanced', 2);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_007', '尿路感染', 'UTI', '["泌尿系统"]', '["犬", "猫"]', '细菌侵入泌尿道并定植繁殖引起的炎症。犬较猫常见。', '["大肠杆菌(最常见)", "葡萄球菌", "逆行性上行感染"]', '细菌经尿道口上行在膀胱黏膜定植引发炎症反应。', '单纯性UTI抗生素治疗预后极好。', 'basic', 1);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_008', '猫下尿路疾病', 'FLUTD', '["泌尿系统"]', '["猫"]', '猫下泌尿道疾病的总称，包括特发性膀胱炎(最常见)、尿结石、尿道梗阻等。', '["特发性膀胱炎(FIC)", "鸟粪石/草酸钙结石", "尿道痉挛", "应激"]', '应激导致交感神经激活，膀胱黏膜通透性增加，钾离子渗入组织层刺激C纤维导致疼痛。', 'FIC易复发，尿道梗阻为急症。', 'intermediate', 4);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_009', '胰腺炎', 'Pancreatitis', '["消化系统"]', '["犬", "猫"]', '胰腺的炎症性疾病。犬多与高脂饮食有关，猫多为特发性或继发于IBD。', '["高脂饮食/高甘油三酯血症", "药物(化疗药)", "创伤", "特发性(猫)"]', '胰酶在胰腺内提前激活导致自身消化，炎症介质释放引发全身炎症反应。', '轻度预后良好，重症坏死性胰腺炎死亡率30-50%。', 'advanced', 3);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_010', '胃肠炎', 'Gastroenteritis', '["消化系统"]', '["犬", "猫"]', '胃和/或肠道的炎症，是最常见的消化系统主诉之一。', '["饮食不当/食物变质", "细菌(沙门氏菌)", "病毒(细小、冠状病毒)", "寄生虫"]', '病原体或刺激物损伤胃肠黏膜导致炎症反应，黏膜屏障破坏导致水电解质分泌异常。', '单纯性预后极好，病毒性细小未免疫幼犬死亡率可达91%。', 'basic', 2);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_011', '异物梗阻', 'Foreign Body', '["消化系统", "外科"]', '["犬", "猫"]', '异物滞留消化道导致机械性梗阻。犬更常见。', '["玩具、骨头、袜子", "毛球(猫)", "线性异物(绳线，猫特有)"]', '异物嵌顿导致局部压迫，静脉回流受阻后动脉供血障碍导致肠壁缺血坏死。', '早期取出预后好，穿孔后并发症风险高。', 'intermediate', 3);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_012', '肝衰竭', 'Liver Failure', '["消化系统"]', '["犬", "猫"]', '肝脏功能严重受损，可分为急性肝衰竭和慢性肝病终末期。', '["药物/毒素(对乙酰氨基酚-猫、木糖醇-犬)", "感染(钩端螺旋体、FIP)", "肿瘤"]', '大量肝细胞坏死导致解毒功能下降(高氨血症)、合成功能下降(低白蛋白)、胆汁排泄障碍(黄疸)。', '急性早期治疗可恢复，终末期预后差。', 'advanced', 3);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_013', '炎症性肠病', 'IBD', '["消化系统"]', '["犬", "猫"]', '特发性慢性胃肠道炎症性疾病，特征为持续性GI症状和组织学炎症。', '["食物过敏/不耐受", "肠道菌群失调", "免疫调节异常"]', '肠黏膜免疫失调导致慢性炎症浸润，黏膜屏障损伤导致吸收不良。', '需长期管理，部分可药物控制。', 'advanced', 2);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_014', '扩张型心肌病', 'DCM', '["心血管系统"]', '["犬"]', '心室腔扩大伴收缩功能降低，是大型犬最常见的获得性心脏病。杜宾、大丹高发。', '["遗传(杜宾、大丹)", "营养缺乏(牛磺酸)", "特发性"]', '心肌收缩力下降导致心输出量降低，代偿性心室扩张进一步加重瓣膜反流。', '预后差，确诊后中位生存期3-6个月。', 'advanced', 3);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_015', '猫肥厚型心肌病', 'HCM', '["心血管系统"]', '["猫"]', '左心室壁和/或室间隔向心性肥厚，是猫最常见的心脏病。缅因猫、布偶猫有遗传倾向。', '["遗传(肌节蛋白基因突变)", "继发于甲亢", "继发于高血压"]', '心肌肥厚导致舒张功能障碍，左房压升高引发肺静脉充血和肺水肿。', '取决于严重程度，合并动脉血栓预后差。', 'advanced', 2);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_016', '心包积液', 'Pericardial Effusion', '["心血管系统"]', '["犬", "猫"]', '心包腔内液体异常积聚，可导致心脏压塞。犬最常见病因是血管肉瘤。', '["血管肉瘤(金毛、德牧)", "心包囊腺癌", "感染性心包炎", "特发性"]', '心包内液体积聚导致心包压升高，心室舒张受限，心输出量急剧下降。', '恶性病因预后极差。', 'advanced', 5);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_017', '糖尿病', 'Diabetes Mellitus', '["内分泌系统"]', '["犬", "猫"]', '胰岛素分泌不足或胰岛素抵抗导致的高血糖综合征。犬多为I型，猫多为II型。', '["自身免疫性beta细胞破坏(犬)", "胰岛素抵抗/肥胖(猫)", "胰腺炎后继发", "药物(糖皮质激素)"]', '胰岛素不足导致葡萄糖利用障碍而高血糖，脂肪分解增加导致酮体生成和酮症酸中毒。', '需终身胰岛素治疗(犬)，猫部分可缓解。', 'intermediate', 2);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_018', '库欣综合征', 'Hyperadrenocorticism', '["内分泌系统"]', '["犬", "猫"]', '肾上腺皮质分泌过多皮质醇导致的临床综合征。犬多为垂体依赖性(85%)。', '["垂体ACTH瘤(85%犬)", "肾上腺肿瘤(15%)", "医源性(长期使用糖皮质激素)"]', '皮质醇过量导致蛋白质分解增加(皮肤变薄、肌肉萎缩)、肝糖异生增加(高血糖)、免疫抑制。', '垂体依赖性经药物控制中位生存期2-3年。', 'advanced', 2);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_019', '猫甲状腺功能亢进', 'Feline Hyperthyroidism', '["内分泌系统"]', '["猫"]', '甲状腺激素过度分泌，是老年猫最常见的内分泌疾病。多为甲状腺腺瘤样增生。', '["甲状腺腺瘤样增生(95%)", "甲状腺腺癌(<5%)"]', 'T3和T4升高导致基础代谢率增加，蛋白质分解增加(体重下降但食欲增加)，心率增加可引发HCM。', '药物或放射性碘治疗效果良好。', 'intermediate', 2);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_020', '甲状腺功能减退', 'Hypothyroidism', '["内分泌系统"]', '["犬"]', '甲状腺激素分泌不足，是犬最常见的内分泌疾病。多为自身免疫性甲状腺炎。', '["自身免疫性淋巴性甲状腺炎", "特发性甲状腺萎缩", "先天性(罕见)"]', 'T3和T4下降导致基础代谢率降低，体重增加、怕冷、嗜睡。', '需终身甲状腺素替代治疗，预后极好。', 'basic', 1);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_021', '乙二醇中毒', 'Ethylene Glycol', '["中毒与急救"]', '["犬", "猫"]', '防冻剂中毒，代谢为草酸钙结晶沉积于肾小管导致AKI。猫致死剂量仅1.5ml/kg。', '["摄入防冻剂(汽车冷却液)", "园林产品", "某些油漆溶剂"]', '乙二醇代谢为草酸，与钙结合形成草酸钙结晶沉积于肾小管导致机械性损伤和缺血。', '犬12-24h内治疗可能存活，猫预后极差。', 'advanced', 5);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_022', '巧克力中毒', 'Chocolate Toxicity', '["中毒与急救"]', '["犬"]', '可可碱和咖啡因中毒，刺激中枢神经系统和心血管系统。黑巧毒性最高。', '["摄入巧克力", "可可制品"]', '可可碱抑制腺苷受体导致中枢兴奋，磷酸二酯酶抑制导致cAMP升高引发心律失常。', '轻度预后好，严重心律失常可致死。', 'basic', 1);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_023', '百合中毒', 'Lily Toxicity', '["中毒与急救"]', '["猫"]', '百合属植物对猫有剧毒，任何部位(包括花粉和水)均可导致AKI。', '["摄入百合属植物", "接触花粉", "饮用百合花瓶水"]', '肾小管上皮细胞坏死导致AKI，机制尚未完全明确。', '摄入后8h内积极治疗可挽救，延误则致死率极高。', 'advanced', 5);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_024', '布洛芬中毒', 'Ibuprofen Toxicity', '["中毒与急救"]', '["犬", "猫"]', 'NSAIDs中毒，猫极为敏感。', '["主人自行喂药", "误食药物", "过量使用"]', 'COX-1抑制导致胃黏膜PG合成减少引发胃溃疡，肾血管收缩导致肾血流减少引发AKI。', '剂量依赖，猫>50mg/kg可致死。', 'basic', 4);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_025', '犬细小病毒病', 'Parvovirus', '["传染病"]', '["犬"]', '高度传染性病毒性肠炎，主要影响未免疫幼犬。特征为严重出血性肠炎和白细胞减少。', '["CPV-2(2a/2b/2c型)", "未免疫/免疫失败"]', '病毒感染肠隐窝上皮导致细胞坏死和肠绒毛萎缩，骨髓抑制导致白细胞急剧下降。', '未治疗死亡率91%，积极治疗存活率80-90%。', 'intermediate', 3);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_026', '犬瘟热', 'Canine Distemper', '["传染病"]', '["犬"]', '犬瘟热病毒引起的多系统感染，可影响呼吸、消化和神经系统。', '["CDV", "未免疫", "接触感染犬分泌物"]', '病毒先在淋巴系统复制后形成病毒血症，多系统感染，神经损伤可为不可逆。', '神经症状出现后预后差，存活犬可能有永久性后遗症。', 'advanced', 3);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_027', '猫泛白细胞减少症', 'Feline Panleukopenia', '["传染病"]', '["猫"]', '猫细小病毒引起的高度传染性病毒病，特征为泛白细胞减少和出血性肠炎。', '["FPV", "未免疫"]', '病毒感染分裂活跃的细胞(肠隐窝、骨髓)导致肠炎和泛白细胞减少。', '未治疗死亡率>90%，积极治疗存活率约50%。', 'intermediate', 4);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_028', '猫传染性腹膜炎', 'FIP', '["传染病"]', '["猫"]', '猫冠状病毒突变引起的免疫介导性血管炎，分为湿性和干性。预后极差。', '["FCoV突变", "多猫环境", "应激", "遗传易感性"]', '突变病毒在巨噬细胞中复制，免疫复合物沉积于血管壁导致血管炎。', '传统观点认为不治之症。', 'advanced', 3);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_029', '胃扩张-扭转', 'GDV', '["外科", "急诊"]', '["犬"]', '胃内气体/液体积聚并发生轴向扭转，是大型深胸犬的致命急症。', '["大型/巨型犬(大丹、德牧)", "老年", "饭后剧烈运动"]', '胃扭转导致贲门和幽门闭塞，胃内压升高导致静脉回流受阻和胃壁缺血坏死。', '术前死亡率15-30%，胃壁坏死需切除则死亡率>50%。', 'advanced', 5);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_030', '子宫蓄脓', 'Pyometra', '["外科", "生殖系统"]', '["犬", "猫"]', '子宫内脓液积聚，是未绝育母犬的常见急症。多在发情后4-8周发生。', '["黄体期孕激素作用", "继发细菌感染(大肠杆菌)", "未绝育中老年母犬"]', '孕激素导致子宫内膜增生、子宫颈关闭，细菌在封闭子宫内繁殖导致脓液蓄积和内毒素吸收。', '手术切除预后极好，延误可致子宫破裂和败血症死亡。', 'intermediate', 3);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_031', '癫痫', 'Epilepsy', '["神经系统"]', '["犬", "猫"]', '大脑神经元异常过度放电导致的反复发作性神经功能障碍。犬多为特发性癫痫，猫多为继发性。', '["特发性/遗传性(犬)", "结构性病变(肿瘤、脑炎)", "代谢性(低血糖、肝性脑病)", "中毒"]', '大脑皮层神经元同步异常放电，GABA能抑制功能下降或谷氨酸能兴奋性增强导致发作阈值降低。', '特发性癫痫经药物控制预后良好，但需终身用药。结构性病因预后取决于原发病。', 'intermediate', 3);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_032', '免疫介导性多关节炎', 'IMPA', '["免疫系统"]', '["犬"]', '免疫系统攻击自身关节滑膜导致的对称性多关节炎症。是犬最常见的免疫介导性疾病之一。', '["特发性(最常见)", "药物反应", "肿瘤相关", "感染后免疫复合物沉积"]', '免疫复合物沉积于滑膜血管壁激活补体，中性粒细胞浸润释放蛋白酶和炎症介质导致滑膜增生和关节软骨破坏。', '早期积极免疫抑制治疗预后良好，但需长期维持。感染性关节炎必须排除。', 'intermediate', 2);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_033', '免疫介导性溶血性贫血', 'IMHA', '["免疫系统", "血液系统"]', '["犬", "猫"]', '免疫系统攻击自身红细胞导致的急性溶血性贫血。犬发病率高，猫多为继发性。致死率高，是内科急症。', '["特发性(犬最常见)", "继发于肿瘤/感染/药物", "猫继发于FeLV/支原体"]', 'IgG或IgM抗体结合红细胞表面抗原，激活补体导致血管内溶血，或巨噬细胞吞噬导致血管外溶血。', '犬死亡率30-50%，合并DIC预后极差。猫继发性IMHA预后取决于原发病。', 'advanced', 4);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_034', '淋巴瘤', 'Lymphoma', '["肿瘤科"]', '["犬", "猫"]', '淋巴细胞的恶性肿瘤，是犬猫最常见的肿瘤类型。犬多为多中心型，猫多为消化道型。', '["遗传易感性(犬)", "FeLV/FIV(猫)", "环境因素(除草剂暴露-犬)", "慢性炎症"]', '淋巴细胞克隆性增殖，侵犯淋巴结、肝脾、骨髓等器官。肿瘤细胞抑制正常造血和免疫功能。', '犬不治疗中位生存期4-6周，化疗后12-14个月。猫低度恶性可达2年。', 'advanced', 3);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_035', '前十字韧带撕裂', 'CCL Tear', '["外科", "骨科"]', '["犬"]', '前十字韧带(ACL)部分或完全断裂，是犬最常见的骨科手术指征。多见于大型犬和肥胖犬。', '["退行性韧带变性(最常见)", "肥胖", "品种易感性(拉布拉多、金毛)", "外伤性(少见)"]', '韧带变性导致机械强度下降，轻微外力即可断裂。关节不稳定导致继发性骨关节炎和半月板损伤。', '手术修复后预后良好，80-90%恢复良好功能。未手术将进行性骨关节炎。', 'intermediate', 2);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_036', '心丝虫病', 'Heartworm Disease', '["寄生虫", "心血管系统"]', '["犬", "猫"]', '犬恶丝虫(Dirofilaria immitis)寄生于肺动脉和右心，通过蚊虫传播。可导致肺动脉高压和右心衰。', '["蚊虫叮咬传播", "未预防用药", "温暖潮湿地区高发"]', '成虫寄生于肺动脉，机械损伤血管内皮引发肺动脉高压。死亡虫体栓塞肺血管可致急性呼吸衰竭。', '犬治疗后预后取决于病变严重程度。猫无特效治疗，以支持治疗为主。预防远优于治疗。', 'intermediate', 3);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_037', '脓皮症', 'Pyoderma', '["皮肤科"]', '["犬"]', '细菌性皮肤感染，是犬最常见的皮肤病。多为浅表性，常继发于过敏、寄生虫或内分泌疾病。', '["葡萄球菌(最常见)", "继发于特应性皮炎/食物过敏", "内分泌疾病(甲减/库欣)", "皮肤褶皱"]', '皮肤屏障破坏后细菌定植繁殖，释放毒素和酶导致炎症反应。深层感染可形成脓肿和蜂窝织炎。', '浅表性抗生素治疗预后极好。深层感染需4-6周抗生素。必须治疗原发病以防复发。', 'basic', 1);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_038', '白内障', 'Cataract', '["眼科"]', '["犬", "猫"]', '晶状体混浊导致视力下降，是犬最常见的眼科疾病之一。糖尿病性白内障是犬最常见的类型，发展迅速。', '["遗传(常见于贵宾、可卡犬)", "糖尿病(犬最常见继发原因)", "老年退行性变", "外伤", "先天性"]', '晶状体纤维变性导致光散射增加，晶状体透明度下降。糖尿病性白内障因高血糖导致山梨醇蓄积，渗透性水肿破坏晶状体纤维。', '手术(超声乳化摘除)后预后良好，视力恢复率90%以上。需控制原发病(如糖尿病)。', 'intermediate', 2);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_039', '青光眼', 'Glaucoma', '["眼科"]', '["犬", "猫"]', '眼内压升高导致视网膜和视神经不可逆损伤，是致盲性眼病。急性闭角型青光眼为眼科急症。', '["原发性(遗传，可卡犬、巴塞特猎犬高发)", "继发性(晶状体脱位、葡萄膜炎、眼内肿瘤)", "先天性"]', '房水排出受阻导致眼内压升高，视网膜神经节细胞缺血性损伤。犬急性眼压>40mmHg可在48-72小时内永久失明。', '早期治疗可延缓进展，已失明者不可逆。需终身管理，对侧眼有发病风险。', 'advanced', 4);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_040', '角膜溃疡', 'Corneal Ulcer', '["眼科"]', '["犬", "猫"]', '角膜上皮缺损，可由外伤、感染、干眼症或眼睑异常引起。深部溃疡和穿孔为眼科急症。', '["外伤(猫抓伤最常见)", "感染(细菌、真菌)", "干眼症(KCS)", "眼睑内翻/倒睫", "暴露性(面神经麻痹)"]', '角膜上皮屏障破坏后基质暴露，胶原酶活化导致基质溶解。深后弹力层膨出可致角膜穿孔。', '浅表溃疡经治疗1-2周内愈合。深部溃疡需手术(角膜移植/结膜瓣)，穿孔预后差。', 'intermediate', 3);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_041', '椎间盘疾病', 'IVDD', '["骨科", "神经系统"]', '["犬"]', '椎间盘退变后突出或脱出压迫脊髓，是犬最常见的脊髓疾病。腊肠犬、比格犬等软骨营养不良品种高发。', '["遗传性软骨营养不良(腊肠犬、比格犬)", "年龄相关退行性变", "外伤"]', '椎间盘髓核钙化后突然突出压迫脊髓，导致脊髓水肿、缺血和神经功能缺损。根据压迫程度分为I-V级。', 'I-II级保守治疗预后好；III-V级需手术减压。深痛觉消失超过48h预后极差。', 'advanced', 3);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_042', '髋关节发育不良', 'Hip Dysplasia', '["骨科"]', '["犬"]', '髋关节窝和股骨头匹配不良导致关节不稳定和退行性关节病，是大型犬最常见的骨科疾病。', '["遗传(金毛、拉布拉多、德牧高发)", "快速生长", "营养过剩(高热量饮食)", "运动不当"]', '髋关节松弛导致半脱位，关节软骨磨损，继发骨关节炎。进行性关节破坏导致疼痛和功能障碍。', '早期干预(幼年骨盆切开术)预后好。成年犬以药物管理和体重控制为主，严重者需股骨头切除或全髋置换。', 'intermediate', 2);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_043', '肥大细胞瘤', 'Mast Cell Tumor', '["肿瘤科"]', '["犬", "猫"]', '肥大细胞来源的肿瘤，是犬最常见的皮肤肿瘤(占20%)，也是猫最常见的皮肤和内脏肿瘤之一。', '["遗传易斗牛犬、拳师犬高发)", "慢性炎症刺激", "c-kit基因突变"]', '肥大细胞脱颗粒释放组胺、肝素等介质，可导致局部红肿、胃溃疡和过敏反应。高分级肿瘤可转移至淋巴结和内脏。', '犬低分级(I-II)手术切除后中位生存期>2年；高分级(III)预后差。猫皮肤型预后好，内脏型预后差。', 'advanced', 3);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_044', '血管肉瘤', 'Hemangiosarcoma', '["肿瘤科"]', '["犬"]', '血管内皮细胞的恶性肿瘤，高度侵袭性和转移性。最常见部位为脾脏、右心和皮下。金毛、德牧高发。', '["遗传易感性(金毛寻回犬)", "紫外线暴露(浅肤色犬皮下型)", "慢性异物刺激"]', '肿瘤生长迅速，易自发性破裂导致致命性出血。早期血行转移至肺、肝和脑。', '极差。单纯手术中位生存期1-3月，联合化疗可延长至6-8月。', 'advanced', 5);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_045', '异位性皮炎', 'Canine Atopic Dermatitis', '["皮肤科"]', '["犬"]', '遗传性过敏反应性炎症性皮肤病，是犬最常见的皮肤病。特征为慢性瘙痒，多始于1-3岁。', '["遗传性IgE介导的超敏反应", "环境过敏原(尘螨、花粉、霉菌)", "皮肤屏障缺陷"]', '过敏原经皮肤进入，被朗格汉斯细胞呈递，Th2型免疫反应导致IgE产生和肥大细胞脱颗粒，释放炎症介质引起瘙痒。', '需终身管理，无法根治。奥克拉珠单抗靶向治疗效果好。继发感染需积极控制。', 'intermediate', 2);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_046', '钩端螺旋体病', 'Leptospirosis', '["传染病"]', '["犬", "猫"]', '人畜共患的螺旋体感染，可导致急性肝肾衰竭。主要通过接触受感染动物尿液污染的水源传播。', '["钩端螺旋体(血清型: icterohaemorrhagiae, canicola, pomona)", "接触污染水源", "野生动物传播"]', '螺旋体经黏膜侵入后血行播散至肝肾，导致肾小管间质性肾炎和肝细胞损伤。', '早期抗生素+支持治疗预后良好。严重肝肾衰竭或肺出血型预后差。可传播给人。', 'intermediate', 4);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_047', '脂肪肝(猫)', 'Hepatic Lipidosis', '["消化系统"]', '["猫"]', '肝细胞内大量甘油三酯蓄积导致肝功能衰竭，是猫最常见的肝病。多由厌食/禁食诱发，肥胖猫高发。', '["厌食/禁食(最常继发于其他疾病)", "肥胖", "糖尿病", "胰腺炎", "甲亢"]', '机体能量需求增加时脂肪大量动员至肝脏，超过肝脏氧化和转运能力导致肝细胞脂肪变性。严重时胆汁排泄障碍导致黄疸。', '积极营养支持(鼻饲/食道饲管)后预后良好，存活率可达80%。延误治疗可致死。', 'intermediate', 4);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_048', '免疫介导性血小板减少症', 'ITP', '["免疫系统", "血液系统"]', '["犬"]', '免疫系统攻击自身血小板导致血小板减少，是犬最常见的获得性出血性疾病。母犬发病率高于公犬。', '["特发性(最常见)", "继发于感染(埃立克体、利什曼)", "药物诱导", "肿瘤相关", "疫苗诱发"]', 'IgG抗体结合血小板表面糖蛋白，被脾脏巨噬细胞吞噬破坏。血小板<30,000/μL时有自发性出血风险。', '单纯ITP经免疫抑制治疗后70-80%可缓解。合并严重出血或DIC预后差。复发率20-30%。', 'advanced', 4);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_049', '犬副流感', 'Canine Parainfluenza', '["传染病"]', '["犬"]', '犬副流感病毒(CPIV)引起的高度传染性呼吸道疾病，是犬窝咳综合征的常见病原之一。', '["犬副流感病毒(CPIV)", "多病原混合感染(博德特氏菌)", "群养环境传播"]', '病毒损伤呼吸道纤毛上皮，破坏黏膜屏障，继发细菌感染加重症状。', '单纯感染5-10天自愈。继发细菌感染需抗生素治疗。预防以疫苗接种为主。', 'basic', 2);
INSERT INTO diseases (id, name_zh, name_en, category, species, overview, etiology, pathophysiology, prognosis, difficulty, urgency_level) VALUES ('dis_050', '子宫蓄脓(猫)', 'Pyometra (Cat)', '["外科", "生殖系统"]', '["猫"]', '猫的子宫蓄脓，与犬类似但发病率较低。未绝育中老年母猫在发情后易发。', '["黄体期孕激素作用", "继发细菌感染", "未绝育母猫"]', '与犬相同，孕激素导致子宫内膜增生和子宫颈关闭，细菌在封闭子宫内繁殖。', '卵巢子宫切除术预后极好。延误可致子宫破裂和败血症。建议早期绝育预防。', 'intermediate', 3);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_001', '咳嗽', 'Cough', '呼吸道受到刺激时产生的保护性反射动作，特征为突然的呼气性爆发声', '{"犬": "区分干咳(气管/支气管)和湿咳(肺实质)", "猫": "需与吐毛球鉴别"}');
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_002', '呼吸困难', 'Dyspnea', '呼吸做功增加的表现，包括张口呼吸、腹式呼吸、头颈伸展', '{"犬": "静息张口呼吸为急症信号", "猫": "张口呼吸在猫几乎总是急症"}');
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_003', '呼吸急促', 'Tachypnea', '呼吸频率异常增快。犬>30次/分，猫>40次/分为异常', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_004', '鼻液', 'Nasal Discharge', '鼻腔分泌物的异常增多，可分为浆液性、黏液性、脓性或血性', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_005', '呕吐', 'Vomiting', '胃内容物经口腔强力排出的复杂反射动作。需与反流鉴别', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_006', '腹泻', 'Diarrhea', '粪便含水量增加、排便频率增加或排便量增加', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_007', '腹痛', 'Abdominal Pain', '腹部不适或疼痛，可表现为弓背、回避触诊、祈祷姿势', '{"犬": "祈祷姿势高度提示胰腺炎", "猫": "表现隐蔽，可能仅表现为躲藏"}');
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_008', '厌食', 'Anorexia', '食欲完全丧失，是许多疾病的非特异性但重要体征', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_009', '体重下降', 'Weight Loss', '非意愿性体重减轻，超过体重10%为临床显著', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_010', '黄疸', 'Icterus', '胆红素沉积导致皮肤、黏膜和巩膜黄染', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_011', '多饮多尿', 'PU/PD', '饮水量和/或尿量异常增多。犬>45ml/kg/day为多饮', '{"犬": "鉴别：糖尿病、CKD、库欣", "猫": "鉴别：糖尿病、CKD、甲亢"}');
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_012', '少尿/无尿', 'Oliguria/Anuria', '尿量显著减少(<1ml/kg/h)或无尿', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_013', '尿频', 'Pollakiuria', '排尿次数增加但每次尿量减少', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_014', '血尿', 'Hematuria', '尿液中存在红细胞', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_015', '腹水', 'Ascites', '腹腔内液体积聚，可由右心衰、低白蛋白血症、肿瘤等引起', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_016', '晕厥', 'Syncope', '短暂性脑血流不足导致的意识丧失', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_017', '运动不耐受', 'Exercise Intolerance', '运动能力下降，轻微活动即出现疲劳或呼吸困难', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_018', '发热', 'Fever', '体温升高超过正常范围。犬>39.2C，猫>39.4C为发热', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_019', '嗜睡', 'Lethargy', '精神状态抑制，活动减少', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_020', '脱水', 'Dehydration', '体液丢失超过摄入，可通过皮肤弹性、黏膜干燥度评估', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_021', '多食', 'Polyphagia', '食欲异常亢进，常见于糖尿病、甲亢(猫)、库欣', '{"猫": "老年猫多食伴体重下降高度怀疑甲亢"}');
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_022', '流涎', 'Drooling', '唾液过度分泌或吞咽障碍导致的唾液外流', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_023', '黏膜苍白', 'Pale Mucous Membranes', '黏膜颜色苍白提示贫血或外周血管收缩(休克)，CRT>2秒为异常', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_024', '后肢瘫痪', 'Paraplegia', '后肢运动功能丧失。在猫需高度警惕动脉血栓(鞍血栓)', '{"猫": "突发后肢瘫痪+皮温低+无脉搏高度怀疑主动脉鞍血栓"}');
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_025', '瘙痒', 'Pruritus', '引起搔抓、舔舐或摩擦欲望的感觉', '{"犬": "注意分布模式", "猫": "常表现为过度理毛而非搔抓"}');
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_026', '癫痫发作', 'Seizure', '大脑神经元异常过度放电导致的突发性临床事件', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_027', '瞳孔散大', 'Mydriasis', '瞳孔异常扩大，对光反射减弱或消失，可见于青光眼、视网膜疾病或神经系统疾病。', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_028', '眼球震颤', 'Nystagmus', '眼球不自主的节律性摆动，可为水平、垂直或旋转性，提示前庭系统或小脑病变。', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_029', '共济失调', 'Ataxia', '运动协调障碍，步态不稳，可见于小脑病变、前庭疾病或脊髓压迫。', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_030', '跛行', 'Lameness', '肢体负重异常导致的步态改变，可见于骨折、关节炎、韧带损伤或神经病变。', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_031', '后肢瘫痪', 'Hindlimb Paralysis', '后肢自主运动功能丧失，可见于椎间盘疾病、脊髓损伤或血栓栓塞。', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_032', '皮肤红斑', 'Erythema', '皮肤发红，由局部血管扩张引起，可见于过敏、感染或自身免疫性皮肤病。', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_033', '皮肤瘙痒', 'Pruritus', '搔抓欲望，是犬猫皮肤病最常见的症状，主要病因为过敏和寄生虫。', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_034', '脱毛', 'Alopecia', '毛发脱落，可为局灶性或全身性，可见于内分泌疾病、寄生虫或真菌感染。', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_035', '黄疸', 'Icterus/Jaundice', '皮肤、黏膜和巩膜黄染，由胆红素升高引起，提示溶血、肝病或胆道梗阻。', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_036', '腹水', 'Ascites', '腹腔内液体积聚，可见于右心衰、肝病、低蛋白血症或腹膜疾病。', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_037', '皮下肿块', 'Subcutaneous Mass', '皮下可触及的肿物，可为脂肪瘤、肥大细胞瘤、囊肿或脓肿。', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_038', '角膜混浊', 'Corneal Opacity', '角膜透明度下降，可见于角膜溃疡、青光眼、角膜水肿或角膜营养不良。', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_039', '眼部分泌物增多', 'Ocular Discharge', '眼部分泌物增加，可为浆液性、黏液性或脓性，提示结膜炎、角膜溃疡或泪道阻塞。', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_040', '流涎', 'Ptyalism/Salivation', '唾液分泌过多或吞咽困难导致唾液外流，可见于口腔疾病、中毒或恶心。', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_041', '里急后重', 'Tenesmus', '排便困难或频繁尝试排便但排出量少，可见于结肠炎、便秘或直肠肿物。', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_042', '血便', 'Hematochezia/Melena', '粪便中带血，鲜红色为下消化道出血（hematochezia），黑色为上消化道出血（melena）。', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_043', '多饮多尿', 'PU/PD', '多饮（polydipsia）和多尿（polyuria）是多种内科疾病的非特异性症状，常见于肾病、糖尿病、库欣等。', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_044', '抽搐', 'Seizures', '肌肉不自主强直或阵挛性收缩，可见于癫痫、中毒、代谢性脑病或颅内占位。', NULL);
INSERT INTO symptoms (id, name_zh, name_en, definition, species_notes) VALUES ('sym_045', '前肢伸展/角弓反张', 'Opisthotonos', '头颈后仰、四肢强直伸展，提示严重脑膜脑炎或破伤风。', NULL);
