INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_001', 'dis_002', '肺炎有发热+湿咳，心衰有心脏杂音+奔马律');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_002', 'dis_014', '心衰MMVD有瓣膜杂音，DCM有心室扩张+心律失常');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_003', 'dis_001', '哮喘有可逆性气流受限+嗜酸性粒细胞增多');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_005', 'dis_006', 'AKI起病急+肾脏可增大，CKD病程长+肾脏缩小');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_009', 'dis_010', '胰腺炎有剧烈腹痛+fPLI升高，胃肠炎腹痛轻且无酶升高');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_009', 'dis_011', '胰腺炎渐进性腹痛+酶升高，异物有吞食史+影像可见异物');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_017', 'dis_018', '糖尿病血糖高+尿糖，库欣有皮肤变薄+ALP升高');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_017', 'dis_019', '糖尿病血糖高但T4正常，甲亢T4升高但血糖可正常');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_019', 'dis_006', '甲亢T4升高+多食体重下降，CKD有氮质血症+尿比重低');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_015', 'dis_016', 'HCM有心室肥厚+左房扩大，心包积液有心包液暗区');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_025', 'dis_027', '细小有严重出血性肠炎+白细胞↓↓，猫泛白细胞减少类似但感染猫细小病毒');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_007', 'dis_008', 'UTI有菌尿+脓尿，FLUTD可能无菌尿');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_010', 'dis_013', '胃肠炎急性起病且自限，IBD慢性持续性+组织学炎症');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_012', 'dis_028', '肝衰竭有凝血障碍+低白蛋白，FIP有渗出液+球蛋白升高');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_021', 'dis_005', '乙二醇中毒有草酸钙结晶+阴离子间隙升高，其他AKI无此特征');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_001', '阿莫西林-克拉维酸', 'Amoxicillin-Clavulanate', '抗生素（β-内酰胺类）', '["尿路感染", "皮肤感染", "软组织感染", "牙周感染", "呼吸道感染"]', '["青霉素过敏", "严重肾功能不全（需调整剂量）"]', '["胃肠道反应（呕吐、腹泻）", "过敏反应", "肠道菌群失调"]', '{"犬": {"dose": "12.5-25 mg/kg", "route": "PO", "frequency": "q12h"}, "猫": {"dose": "12.5-25 mg/kg", "route": "PO", "frequency": "q12h"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_002', '恩诺沙星', 'Enrofloxacin', '抗生素（氟喹诺酮类）', '["尿路感染", "皮肤感染", "呼吸道感染", "前列腺炎", "革兰阴性菌感染"]', '["幼龄动物（软骨毒性）", "猫高剂量（视网膜毒性）", "癫痫病史"]', '["胃肠道反应", "中枢神经系统兴奋", "幼畜软骨损伤", "猫视网膜病变（高剂量）"]', '{"犬": {"dose": "5-20 mg/kg", "route": "PO/IV/SC", "frequency": "q24h"}, "猫": {"dose": "2.5-5 mg/kg", "route": "PO", "frequency": "q24h（不超过5mg/kg）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_003', '呋塞米', 'Furosemide', '利尿剂（袢利尿剂）', '["充血性心力衰竭", "肺水肿", "胸腔积液", "急性肾损伤（促进利尿）", "高钙血症"]', '["脱水", "无尿", "低钾血症", "磺胺类过敏"]', '["脱水", "低钾血症", "低钠血症", "耳毒性（高剂量IV）", "肾前性氮质血症"]', '{"犬": {"dose": "2-4 mg/kg", "route": "IV/IM/PO", "frequency": "q8-12h（急性）；1-2 mg/kg q12-24h（维持）"}, "猫": {"dose": "1-2 mg/kg", "route": "IV/IM/PO", "frequency": "q12-24h"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_004', '泼尼松龙', 'Prednisolone', '糖皮质激素', '["炎症性肠病", "过敏/特应性皮炎", "免疫介导性疾病", "猫哮喘", "肿瘤化疗辅助", "肾上腺皮质功能减退"]', '["真菌感染", "消化性溃疡", "未控制的糖尿病", "库欣综合征", "妊娠"]', '["多饮多尿多食", "胃肠道溃疡", "肌肉萎缩", "皮肤变薄", "免疫抑制", "医源性库欣"]', '{"犬": {"dose": "0.5-1 mg/kg", "route": "PO", "frequency": "q12h（抗炎）；0.1-0.25 mg/kg q48h（替代）"}, "猫": {"dose": "1-2 mg/kg", "route": "PO", "frequency": "q12h（抗炎，猫需更高剂量）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_005', '胰岛素（甘精胰岛素）', 'Insulin Glargine', '胰岛素（长效）', '["犬糖尿病（I型）", "猫糖尿病（II型，部分可缓解）", "糖尿病酮症酸中毒（急性期后）"]', '["低血糖", "胰岛素瘤"]', '["低血糖（最严重）", "注射部位反应", "体重增加", "Somogyi效应（反跳性高血糖）"]', '{"犬": {"dose": "0.25-0.5 U/kg", "route": "SC", "frequency": "q12h"}, "猫": {"dose": "0.25-0.5 U/kg", "route": "SC", "frequency": "q12h（猫对胰岛素敏感，需谨慎调整）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_006', '匹莫苯丹', 'Pimobendan', '正性肌力药（PDE-3抑制剂+钙增敏剂）', '["充血性心力衰竭（MMVD/DCM）", "扩张型心肌病", "二尖瓣关闭不全"]', '["肥厚型心肌病（HCM）", "主动脉瓣下狭窄", "心包填塞"]', '["心律失常", "食欲下降", "腹泻", "多动（正性肌力作用）"]', '{"犬": {"dose": "0.2-0.3 mg/kg", "route": "PO", "frequency": "q12h（餐前1h给药）"}, "猫": {"dose": "0.1-0.25 mg/kg", "route": "PO", "frequency": "q12h（猫数据有限）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_007', '甲巯咪唑', 'Methimazole', '抗甲状腺药物（硫脲类）', '["猫甲状腺功能亢进", "甲亢术前准备"]', '["严重肝功能不全", "严重肾功能不全", "妊娠（猫）"]', '["呕吐/厌食", "面部瘙痒（猫）", "血液学毒性（粒细胞减少）", "血小板减少", "肝毒性"]', '{"猫": {"dose": "2.5 mg", "route": "PO/Transdermal", "frequency": "q12h（猫用透皮耳膏更安全）"}, "犬": {"dose": "不适用（犬甲亢极罕见）", "route": "-", "frequency": "-"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_008', '左甲状腺素钠', 'Levothyroxine (T4)', '甲状腺激素替代', '["犬甲状腺功能减退"]', '["甲状腺功能亢进", "肾上腺皮质功能减退（需先补充糖皮质激素）", "未纠正的肾上腺功能不全"]', '["多动/焦虑", "多饮多尿", "心动过速", "体重下降（过量时）"]', '{"犬": {"dose": "0.02 mg/kg", "route": "PO", "frequency": "q12h"}, "猫": {"dose": "不适用（猫甲减极罕见）", "route": "-", "frequency": "-"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_009', '奥美拉唑', 'Omeprazole', '质子泵抑制剂（PPI）', '["胃酸相关疾病", "消化性溃疡", "NSAIDs胃保护", "胰腺炎辅助", "胃食管反流"]', '["严重肝功能不全（需减量）"]', '["胃肠道反应（少见）", "长期用可能影响钙吸收"]', '{"犬": {"dose": "0.5-1 mg/kg", "route": "PO", "frequency": "q24h（空腹给药）"}, "猫": {"dose": "0.7-1 mg/kg", "route": "PO", "frequency": "q24h（空腹给药）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_010', '马罗匹坦', 'Maropitant (Cerenia)', 'NK-1受体拮抗剂（止吐药）', '["急性呕吐", "晕动症（犬）", "化疗相关呕吐", "胰腺炎辅助止吐"]', '["16周龄以下犬", "胃肠道梗阻", "严重肝功能不全"]', '["注射部位疼痛（SC）", "流涎（犬）", "腹泻", "食欲下降"]', '{"犬": {"dose": "1 mg/kg SC 或 2 mg/kg PO", "route": "SC/PO", "frequency": "q24h（不超过5天连续SC）"}, "猫": {"dose": "1 mg/kg", "route": "SC/PO", "frequency": "q24h（猫标签外使用）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_011', '曲马多', 'Tramadol', '阿片类镇痛药（弱）', '["中度疼痛", "术后疼痛", "骨关节炎疼痛", "慢性疼痛管理"]', '["癫痫病史", "与MAO抑制剂合用", "严重肝肾功能不全"]', '["镇静", "恶心/呕吐", "便秘", "瞳孔缩小", "唾液分泌增加（猫）"]', '{"犬": {"dose": "2-5 mg/kg", "route": "PO", "frequency": "q8-12h"}, "猫": {"dose": "2-4 mg/kg", "route": "PO", "frequency": "q12h（猫代谢个体差异大）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_012', '美洛昔康', 'Meloxicam', 'NSAIDs（COX-2选择性抑制剂）', '["骨关节炎疼痛", "术后镇痛", "软组织损伤", "慢性炎症"]', '["脱水/低血容量", "消化道溃疡", "肾功能不全", "肝功能不全", "与其他NSAIDs或糖皮质激素合用"]', '["胃肠道溃疡/呕吐/腹泻", "肾毒性", "肝毒性", "凝血障碍"]', '{"犬": {"dose": "0.1 mg/kg", "route": "PO", "frequency": "q24h（首剂可0.2 mg/kg）"}, "猫": {"dose": "0.05 mg/kg", "route": "PO/SC", "frequency": "q24h（猫单次SC注射后转为口服，不超过3天）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_013', '多西环素', 'Doxycycline', '抗生素（四环素类）', '["立克次体病（埃立克体、落基山斑疹热）", "支原体/衣原体感染", "莱姆病", "钩端螺旋体病", "心丝虫辅助"]', '["妊娠", "8周龄以下幼畜（牙齿着色风险）", "严重肝功能不全"]', '["食管狭窄（猫，给药后需冲水）", "呕吐/腹泻", "光敏反应", "肝毒性（罕见）"]', '{"犬": {"dose": "5-10 mg/kg", "route": "PO", "frequency": "q12h（首剂加倍）"}, "猫": {"dose": "5 mg/kg", "route": "PO", "frequency": "q12h（给药后冲水防食管狭窄）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_014', '甲硝唑', 'Metronidazole', '抗生素/抗原虫（硝基咪唑类）', '["厌氧菌感染", "贾第鞭毛虫", "炎症性肠病（免疫调节）", "肝性脑病", "坏死性肠炎"]', '["妊娠（早期）", "严重肝病", "与华法林合用"]', '["神经毒性（高剂量，共济失调/眼球震颤）", "食欲下降", "呕吐", "肝毒性（高剂量）"]', '{"犬": {"dose": "10-15 mg/kg", "route": "PO", "frequency": "q12h"}, "猫": {"dose": "10-15 mg/kg", "route": "PO", "frequency": "q12h（猫更易出现神经毒性）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_015', '地高辛', 'Digoxin', '强心苷类正性肌力药', '["充血性心力衰竭", "心房颤动（心室率控制）", "室上性心动过速"]', '["心室颤动", "肥厚型心肌病", "二度/三度房室传导阻滞", "低钾血症", "肾功能不全（需减量）"]', '["心律失常（治疗窗窄）", "厌食/呕吐/腹泻", "嗜睡", "视觉障碍"]', '{"犬": {"dose": "0.0025-0.005 mg/kg", "route": "PO", "frequency": "q12h（监测血药浓度）"}, "猫": {"dose": "0.001-0.002 mg/kg", "route": "PO", "frequency": "q24-48h（猫极敏感）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_016', '苯巴比妥', 'Phenobarbital', '抗癫痫药（巴比妥类）', '["癫痫（一线用药）", "特发性癫痫", "癫痫持续状态（IV地西泮控制后维持）"]', '["严重肝病", "严重呼吸抑制"]', '["镇静/共济失调（初期）", "多饮多尿多食", "肝毒性（长期）", "血液学毒性（罕见）"]', '{"犬": {"dose": "2-5 mg/kg", "route": "PO", "frequency": "q12h（需监测血药浓度）"}, "猫": {"dose": "2-3 mg/kg", "route": "PO", "frequency": "q12h"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_017', '溴化钾', 'Potassium Bromide', '抗癫痫药', '["癫痫（单药或联合苯巴比妥）", "苯巴比妥不耐受的癫痫病例"]', '["肾功能不全", "对溴化物过敏"]', '["镇静/共济失调", "多饮多尿", "胰腺炎（犬）", "皮肤疹"]', '{"犬": {"dose": "30-40 mg/kg", "route": "PO", "frequency": "q24h（负荷剂量可加倍）"}, "猫": {"dose": "不适用（猫溴化物可致致命性肺炎）", "route": "-", "frequency": "-"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_018', '阿莫西林', 'Amoxicillin', '抗生素（β-内酰胺类，氨基青霉素）', '["尿路感染", "皮肤感染", "呼吸道感染", "牙科感染", "软组织感染"]', '["青霉素过敏"]', '["胃肠道反应", "过敏反应", "肠道菌群失调"]', '{"犬": {"dose": "11-22 mg/kg", "route": "PO", "frequency": "q12h"}, "猫": {"dose": "11-22 mg/kg", "route": "PO", "frequency": "q12h"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_019', '头孢氨苄', 'Cefalexin', '抗生素（第一代头孢菌素）', '["皮肤感染", "尿路感染", "软组织感染", "骨关节感染"]', '["青霉素/头孢菌素过敏", "严重肾功能不全（需调整剂量）"]', '["胃肠道反应", "过敏反应", "注射部位疼痛（IM）"]', '{"犬": {"dose": "22-30 mg/kg", "route": "PO", "frequency": "q12h"}, "猫": {"dose": "22-30 mg/kg", "route": "PO", "frequency": "q12h"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_020', '氟苯尼考', 'Florfenicol', '抗生素（苯丙醇类）', '["呼吸道感染（尤其牛呼吸道病）", "皮肤感染", "多药耐药菌感染"]', '["妊娠", "疫苗接种期间", "家禽（禁用）"]', '["胃肠道反应", "骨髓抑制（罕见）", "注射部位反应"]', '{"犬": {"dose": "20 mg/kg", "route": "PO/SC", "frequency": "q8-12h"}, "猫": {"dose": "标签外使用，数据有限", "route": "PO", "frequency": "谨慎使用"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_021', '特比萘芬', 'Terbinafine', '抗真菌药（丙烯胺类）', '["皮肤真菌病（癣菌）", "甲真菌病", "马拉色菌感染"]', '["严重肝功能不全"]', '["胃肠道反应", "肝酶升高", "味觉障碍（罕见）"]', '{"犬": {"dose": "30 mg/kg", "route": "PO", "frequency": "q24h"}, "猫": {"dose": "20-40 mg/kg", "route": "PO", "frequency": "q24h（猫对疗程要求更长）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_022', '伊曲康唑', 'Itraconazole', '抗真菌药（三唑类）', '["深部真菌病（组织胞浆菌、球孢子菌、隐球菌）", "皮肤真菌病", "曲霉菌病"]', '["严重肝病", "妊娠", "与某些心脏药物合用"]', '["肝毒性", "胃肠道反应", "皮肤溃疡（犬脉冲疗法时）", "食欲下降"]', '{"犬": {"dose": "5-10 mg/kg", "route": "PO", "frequency": "q12-24h（与食物同服）"}, "猫": {"dose": "5-10 mg/kg", "route": "PO", "frequency": "q24h（液体剂型优于胶囊）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_023', '多拉西泮（安定）', 'Diazepam', '苯二氮卓类', '["癫痫持续状态（IV）", "焦虑/行为问题", "术前镇静", "骨骼肌痉挛", "猫特发性膀胱炎（急性期）"]', '["严重肝功能不全（猫口服可致致命性肝坏死）", "重症肌无力", "严重呼吸抑制"]', '["镇静/共济失调", "肝毒性（猫口服）", "兴奋性矛盾反应（猫）", "呼吸抑制（IV）"]', '{"犬": {"dose": "0.5-2 mg/kg IV（癫痫持续状态）；0.2-0.5 mg/kg PO", "route": "IV/PO", "frequency": "按需"}, "猫": {"dose": "0.5-1 mg/kg IV（癫痫持续状态）", "route": "IV", "frequency": "按需（避免口服，肝毒性风险）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_024', '阿替美唑', 'Atipamezole', 'α-2肾上腺素能受体拮抗剂（右美托咪定拮抗剂）', '["右美托咪定/美托咪定麻醉后逆转", "镇静逆转"]', '["妊娠", "心脏病（相对）"]', '["短暂性低血压", "呕吐", "兴奋/躁动", "心动过速"]', '{"犬": {"dose": "与右美托咪定等量（mg）", "route": "IM", "frequency": "单次"}, "猫": {"dose": "与右美托咪定等量（mg）", "route": "IM", "frequency": "单次"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_025', '纳洛酮', 'Naloxone', '阿片受体拮抗剂', '["阿片类药物过量逆转", "术后阿片类药物残余效应"]', '["阿片类药物依赖动物（可诱发戒断）"]', '["疼痛反弹", "心动过速", "兴奋/躁动", "肺水肿（罕见，快速IV）"]', '{"犬": {"dose": "0.01-0.04 mg/kg", "route": "IV/IM/SC", "frequency": "可重复（作用时间短于阿片类）"}, "猫": {"dose": "0.01-0.04 mg/kg", "route": "IV/IM/SC", "frequency": "可重复"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_026', '维生素K1', 'Phytonadione (Vitamin K1)', '维生素/凝血因子合成辅助', '["香豆素类灭鼠药中毒", "华法林过量", "严重肝病凝血障碍", "新生畜维生素K缺乏"]', '["无特殊绝对禁忌"]', '["过敏反应（IV）", "注射部位反应", "高铁血红蛋白血症（极高剂量）"]', '{"犬": {"dose": "2-5 mg/kg", "route": "PO/SC", "frequency": "q12-24h（随脂餐口服）；疗程2-4周（灭鼠药中毒）"}, "猫": {"dose": "2-5 mg/kg", "route": "PO/SC", "frequency": "q12-24h（猫对灭鼠药更敏感）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_027', '硫糖铝', 'Sucralfate', '胃黏膜保护剂', '["消化道溃疡", "NSAIDs相关胃损伤", "尿毒症胃炎", "食管炎"]', '["严重肾功能不全（铝蓄积风险）"]', '["便秘", "铝蓄积（长期/肾衰）", "影响其他药物吸收（需间隔2h）"]', '{"犬": {"dose": "0.5-1 g", "route": "PO", "frequency": "q8-12h（空腹）"}, "猫": {"dose": "0.25 g", "route": "PO", "frequency": "q8-12h（空腹）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_028', '多库酯钠', 'Docusate Sodium (DSS)', '粪便软化剂/灌肠剂', '["便秘", "巨结肠（猫）", "粪便嵌塞", "灌肠（DSS灌肠液）"]', '["肠梗阻", "消化道穿孔"]', '["腹泻", "电解质紊乱（长期口服）", "灌肠时黏膜刺激"]', '{"犬": {"dose": "50-200 mg", "route": "PO", "frequency": "q12-24h"}, "猫": {"dose": "50 mg", "route": "PO", "frequency": "q24h"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_029', '乳酸林格液', 'Lactated Ringer''s Solution', '晶体液（等渗）', '["脱水补液", "围手术期液体支持", "低血容量休克", "电解质紊乱纠正", "维持输液"]', '["高钙血症（含钙）", "严重乳酸酸中毒", "高钾血症"]', '["液体过负荷", "低钾血症（稀释性）", "静脉炎（外周输注）"]', '{"犬": {"dose": "10-30 ml/kg/h（急性休克）；40-60 ml/kg/day（维持）", "route": "IV", "frequency": "持续"}, "猫": {"dose": "3-5 ml/kg/h（急性）；2-4 ml/kg/h（维持）", "route": "IV", "frequency": "持续（猫易过负荷）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_030', '活性炭', 'Activated Charcoal', '吸附剂（解毒）', '["中毒急救（吸附胃肠道毒物）", "某些药物过量", "乙二醇中毒辅助"]', '["肠梗阻/穿孔", "腐蚀性物质中毒", "无保护气道（误吸风险）"]', '["呕吐/误吸", "便秘/肠梗阻", "高钠血症（含山梨醇制剂）", "黑便"]', '{"犬": {"dose": "1-4 g/kg（首剂）", "route": "PO", "frequency": "q4-8h（含山梨醇制剂不超过2次）"}, "猫": {"dose": "1-4 g/kg（首剂）", "route": "PO", "frequency": "q4-8h（猫需更小体积，注意误吸风险）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_031', '托芬那酸', 'Tolfenamic Acid', 'NSAIDs（芬那酸类）', '["术后镇痛", "骨关节炎", "软组织炎症", "发热（猫）"]', '["脱水/低血容量", "消化道溃疡", "肾功能不全", "肝功能不全", "妊娠"]', '["胃肠道反应", "肾毒性", "肝毒性", "注射部位反应（SC）"]', '{"犬": {"dose": "4 mg/kg", "route": "SC/PO", "frequency": "单次SC或q24h PO（不超过3天）"}, "猫": {"dose": "4 mg/kg", "route": "SC", "frequency": "单次（猫仅批准单次SC注射）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_032', '加巴喷丁', 'Gabapentin', '抗癫痫药/神经性镇痛药', '["神经性疼痛", "慢性疼痛（联合NSAIDs）", "术后镇痛辅助", "焦虑（猫术前）", "难治性癫痫辅助"]', '["严重肾功能不全（需减量）"]', '["镇静/共济失调", "外周水肿", "含Xylitol的口服液（犬禁用）"]', '{"犬": {"dose": "5-10 mg/kg", "route": "PO", "frequency": "q8-12h（镇痛）；3-5 mg/kg q8h（起始）"}, "猫": {"dose": "5-10 mg/kg", "route": "PO", "frequency": "q8-12h（镇痛/术前镇静）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_033', '氯胺酮', 'Ketamine', '分离麻醉剂（NMDA受体拮抗剂）', '["诱导麻醉", "镇痛（亚麻醉剂量）", "癫痫持续状态", "安乐死（辅助）"]', '["严重高血压", "颅内压升高", "严重肝病", "单独使用（需联合镇静剂）"]', '["唾液分泌增加", "肌肉僵直", "精神性反应（猫）", "呼吸抑制（高剂量）", "惊厥阈值降低"]', '{"犬": {"dose": "5-10 mg/kg IV（诱导，联合镇静剂）", "route": "IV/IM", "frequency": "按需"}, "猫": {"dose": "5-10 mg/kg IV（诱导）", "route": "IV/IM", "frequency": "按需（猫可单独用于制动）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_034', '布托啡诺', 'Butorphanol', '阿片类镇痛药（激动-拮抗剂）', '["中度至重度疼痛", "术前镇痛", "术后镇痛", "内脏痛"]', '["严重肝肾功能不全", "与纯阿片激动剂合用（可拮抗其作用）"]', '["镇静", "流涎", "共济失调", "食欲下降", "呼吸抑制（高剂量）"]', '{"犬": {"dose": "0.2-0.4 mg/kg", "route": "IV/IM/SC", "frequency": "q2-4h（镇痛）；0.25-0.5 mg/kg PO q6-8h"}, "猫": {"dose": "0.2-0.4 mg/kg", "route": "IV/IM/SC", "frequency": "q2-4h（猫对布托啡诺敏感，镇痛效果好）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_035', '布地奈德', 'Budesonide', '糖皮质激素（局部作用）', '["炎症性肠病（IBD）", "慢性肠病", "结肠炎"]', '["真菌感染", "妊娠", "对布地奈德过敏"]', '["医源性库欣（长期高剂量）", "肾上腺抑制", "胃肠道反应（少见）"]', '{"犬": {"dose": "1-3 mg/只（小型犬1mg，大型犬3mg）", "route": "PO", "frequency": "q24h（逐渐减量）"}, "猫": {"dose": "1 mg/只", "route": "PO", "frequency": "q24h（猫IBD治疗）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_036', '司来吉兰', 'Selegiline (L-Deprenyl)', '单胺氧化酶-B抑制剂（MAO-B抑制剂）', '["犬库欣综合征（垂体依赖型）", "犬认知功能障碍综合征（CDS）"]', '["与SSRI类抗抑郁药合用", "与哌替啶合用", "妊娠"]', '["呕吐/厌食", "焦虑/兴奋", "心动过速", "嗜睡", "耳部瘙痒"]', '{"犬": {"dose": "1 mg/kg", "route": "PO", "frequency": "q24h（库欣）；0.5-1 mg/kg q24h（CDS）"}, "猫": {"dose": "不适用（猫司来吉兰疗效未证实）", "route": "-", "frequency": "-"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_037', '曲唑酮', 'Trazodone', '5-HT受体拮抗剂/再摄取抑制剂（SARI类）', '["焦虑/行为问题", "术前镇静", "术后笼养镇静", "噪音恐惧症", "分离焦虑"]', '["与MAO抑制剂合用", "严重肝功能不全", "已知QT延长"]', '["镇静（最常见）", "共济失调", "胃肠道反应", "激越（少见）", "阴茎异常勃起（犬，未去势）"]', '{"犬": {"dose": "2-5 mg/kg", "route": "PO", "frequency": "q8-12h（镇静/焦虑）；术前2-3h给予5-10 mg/kg"}, "猫": {"dose": "50-100 mg/只", "route": "PO", "frequency": "q24h（猫标签外使用，数据有限）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_038', '贝那普利', 'Benazepril', '血管紧张素转换酶抑制剂（ACEI）', '["慢性肾病（减少蛋白尿）", "心力衰竭辅助", "高血压"]', '["双侧肾动脉狭窄", "妊娠", "严重肾功能不全（需谨慎）", "低血压"]', '["低血压", "高钾血症", "食欲下降", "呕吐/腹泻", "肾功能恶化（罕见）"]', '{"犬": {"dose": "0.25-0.5 mg/kg", "route": "PO", "frequency": "q24h"}, "猫": {"dose": "0.25-0.5 mg/kg", "route": "PO", "frequency": "q24h（猫CKD蛋白尿管理）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_039', '碳酸镧', 'Lanthanum Carbonate', '磷酸盐结合剂', '["高磷血症（CKD相关）", "慢性肾病矿物质代谢紊乱"]', '["低磷血症", "肠梗阻"]', '["胃肠道反应（恶心/呕吐）", "便秘", "电解质紊乱"]', '{"犬": {"dose": "30-90 mg/kg", "route": "PO", "frequency": "q24h（与食物同服）"}, "猫": {"dose": "30-60 mg/kg", "route": "PO", "frequency": "q24h（与食物同服）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_040', '乙酰丙嗪', 'Acepromazine', '吩噻嗪类镇静剂', '["术前镇静", "镇静/制动", "镇吐辅助", "化学保定"]', '["癫痫（降低惊厥阈值）", "严重心血管疾病", "妊娠", "拳师犬（易晕厥）", "老年/体弱动物"]', '["镇静", "低血压", "心动过缓", "低体温", "阴茎异常勃起/脱垂（未去势公犬，罕见但严重）"]', '{"犬": {"dose": "0.02-0.05 mg/kg", "route": "IV/IM/SC", "frequency": "按需（镇静）；0.5-2.2 mg/kg PO q6-8h"}, "猫": {"dose": "0.02-0.05 mg/kg", "route": "IV/IM/SC", "frequency": "按需（镇静）；1-2 mg/kg PO q8-12h"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_041', '氯雷他定', 'Loratadine', '抗组胺药（H1受体拮抗剂，第二代）', '["过敏/特应性皮炎", "荨麻疹", "过敏性鼻炎", "跳蚤过敏性皮炎辅助"]', '["严重肝功能不全（需减量）"]', '["镇静（少见，第二代抗组胺药镇静作用轻）", "胃肠道反应", "口干"]', '{"犬": {"dose": "0.5-1 mg/kg", "route": "PO", "frequency": "q24h"}, "猫": {"dose": "5 mg/只", "route": "PO", "frequency": "q24h（猫标签外使用）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_042', '苯巴比妥', 'Phenobarbital', '抗癫痫药（巴比妥类）', '["犬特发性癫痫", "癫痫持续状态（IV）", "猫癫痫（二线）"]', '["严重肝病", "妊娠", "与氯丙嗪合用（降低惊厥阈值）"]', '["镇静/共济失调（起始期常见）", "多饮多尿多食", "肝毒性（长期）", "再生障碍性贫血（罕见）"]', '{"犬": {"dose": "2-5 mg/kg", "route": "PO", "frequency": "q12h（维持）；20 mg/kg IV（癫痫持续状态）"}, "猫": {"dose": "2-3 mg/kg", "route": "PO", "frequency": "q12h（猫二线用药）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_043', '溴化钾', 'Potassium Bromide', '抗癫痫药（溴化物）', '["犬难治性癫痫（联合苯巴比妥）", "苯巴比妥不耐受时的替代"]', '["肾功能不全", "妊娠", "与含溴药物合用"]', '["镇静/共济失调（起始期）", "多饮多尿多食", "胃肠道反应", "皮肤反应（罕见）"]', '{"犬": {"dose": "30-40 mg/kg", "route": "PO", "frequency": "q24h（维持）；负荷剂量200-300 mg/kg 分5天给予"}, "猫": {"dose": "不适用（猫溴化物耐受差，可致支气管痉挛）", "route": "-", "frequency": "-"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_044', '硫唑嘌呤', 'Azathioprine', '免疫抑制剂（嘌呤类似物）', '["免疫介导性疾病（IMHA/IMPA）", "炎症性肠病（激素节约剂）", "自身免疫性皮肤病"]', '["妊娠", "严重肝病", "与别嘌醇合用（毒性增加）"]', '["骨髓抑制（WBC↓）", "胃肠道反应", "肝毒性", "胰腺炎（犬）"]', '{"犬": {"dose": "2 mg/kg", "route": "PO", "frequency": "q24h（诱导）；q48h（维持）"}, "猫": {"dose": "0.3 mg/kg", "route": "PO", "frequency": "q48-72h（猫对硫唑嘌呤敏感，代谢慢）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_045', '环磷酰胺', 'Cyclophosphamide', '烷化剂（化疗药）', '["淋巴瘤（CHOP方案）", "免疫介导性疾病（严重）", "肿瘤化疗"]', '["妊娠", "严重骨髓抑制", "活动性感染", "严重肝病"]', '["骨髓抑制", "胃肠道反应", "出血性膀胱炎（犬）", "脱发（有毛品种）"]', '{"犬": {"dose": "50 mg/m²", "route": "PO", "frequency": "q48h（CHOP方案中）；200 mg/m² IV 每周一次"}, "猫": {"dose": "10 mg/kg", "route": "IV", "frequency": "每2-3周（猫CHOP方案剂量较低）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_046', '长春新碱', 'Vincristine', '植物碱类化疗药（长春花生物碱）', '["淋巴瘤（CHOP方案）", "犬血小板减少症（ITP）"]', '["妊娠", "严重骨髓抑制", "肝静脉闭塞病"]', '["外周神经毒性", "胃肠道反应", "局部组织坏死（渗漏）", "骨髓抑制（较轻）"]', '{"犬": {"dose": "0.5-0.75 mg/m²", "route": "IV", "frequency": "每周一次（CHOP方案）"}, "猫": {"dose": "0.5-0.7 mg/m²", "route": "IV", "frequency": "每周一次（猫CHOP方案）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_047', '多柔比星', 'Doxorubicin', '蒽环类化疗药', '["淋巴瘤（CHOP方案）", "血管肉瘤", "骨肉瘤", "多种实体瘤"]', '["心脏病（累积心脏毒性）", "严重肝病", "妊娠", "累积剂量限制"]', '["骨髓抑制", "心脏毒性（累积剂量相关）", "胃肠道反应", "局部组织坏死（渗漏）", "脱毛"]', '{"犬": {"dose": "30 mg/m²（≥10kg）或1 mg/kg（<10kg）", "route": "IV", "frequency": "每3周（累积上限180-240 mg/m²）"}, "猫": {"dose": "20-25 mg/m²", "route": "IV", "frequency": "每3周（猫剂量较低）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_048', '美拉索明', 'Melarsomine', '有机砷化合物（杀心丝虫药）', '["犬心丝虫病（杀成虫）"]', '["严重心丝虫病（IV期，手术取虫更安全）", "妊娠", "肝肾功能严重不全"]', '["注射部位疼痛/肿胀", "肺血栓栓塞（死亡虫体）", "肝毒性", "发热/厌食"]', '{"犬": {"dose": "2.5 mg/kg", "route": "IM（深部腰肌注射）", "frequency": "第1天1次→第2天2次（间隔24h）= 3次注射方案"}, "猫": {"dose": "不推荐（猫对美拉索明毒性大，无安全有效剂量）", "route": "-", "frequency": "-"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_049', '伊维菌素', 'Ivermectin', '大环内酯类抗寄生虫药', '["心丝虫预防", "疥螨", "耳螨", "肠道线虫", "微丝蚴清除"]', '["柯利犬/牧羊犬MDR1基因突变（高剂量神经毒性）", "6周龄以下幼犬"]', '["呕吐/腹泻", "镇静/共济失调（MDR1突变犬高剂量时）", "瞳孔散大"]', '{"犬": {"dose": "6-12 μg/kg", "route": "PO", "frequency": "每月一次（心丝虫预防）"}, "猫": {"dose": "24 μg/kg", "route": "PO", "frequency": "每月一次（猫心丝虫预防剂量）"}}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_050', '多库酯钠/乳果糖', 'Docusate/Lactulose', '消化系统用药', '["便秘", "肝性脑病(乳果糖)"]', '["肠梗阻"]', '["腹泻", "电解质紊乱(长期使用)"]', NULL);
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_051', '马罗匹坦', 'Maropitant', '止吐药', '["各种原因呕吐", "预防晕动症"]', '["16周龄以下犬"]', '["注射部位疼痛", "一过性心动过缓"]', '"犬：口服2mg/kg q24h；皮下注射1mg/kg q24h（连用最多5天）；猫：口服1mg/kg q24h"');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_052', '加巴喷丁', 'Gabapentin', '抗癫痫药/镇痛药', '["神经性疼痛", "癫痫辅助", "焦虑/应激"]', '["严重肾功能不全"]', '["镇静", "共济失调", "外周水肿"]', '"犬：5-10mg/kg q8-12h；猫：5-10mg/kg q12h"');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_053', '曲马多', 'Tramadol', '镇痛药', '["轻至中度疼痛", "慢性疼痛"]', '["MAO抑制剂合用", "癫痫患犬慎用"]', '["镇静", "恶心", "便秘", "猫可能产生兴奋而非镇静"]', '"犬：2-5mg/kg q8-12h；猫：效果不确切，2-4mg/kg q12h"');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_054', '托赛米', 'Torasemide', '利尿剂', '["心力衰竭", "其他需强利尿的情况"]', '["低血容量", "低钾血症", "肝昏迷"]', '["脱水", "电解质紊乱", "肾前性氮质血症"]', '"犬：0.1-0.3mg/kg q24h（口服）；猫：0.1-0.2mg/kg q24h"');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_055', '贝那普利', 'Benazepril', 'ACE抑制剂', '["CKD蛋白尿", "心力衰竭", "高血压"]', '["双侧肾动脉狭窄", "妊娠"]', '["低血压", "高钾血症", "肾功能恶化"]', '"犬猫：0.25-0.5mg/kg q24h"');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_056', '氯吡格雷', 'Clopidogrel', '抗血小板药', '["血栓预防(猫HCM)", "动脉血栓栓塞"]', '["活动性出血", "严重肝病"]', '["出血倾向", "胃肠道不适"]', '"猫：18.75mg/cat q24h；犬：1-2mg/kg q24h"');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_057', '阿替帕唑', 'Atipamezole', '拮抗剂', '["逆转α2激动剂镇静"]', '[]', '["一过性低血压", "呕吐", "兴奋"]', '"犬猫：给予美托咪定等量（mg:mg）IM"');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_058', '氟西汀', 'Fluoxetine', '行为调节药', '["分离焦虑", "强迫行为", "猫喷尿标记"]', '["MAO抑制剂合用", "癫痫病史"]', '["食欲下降", "镇静", "胃肠道不适"]', '"犬：1-2mg/kg q24h；猫：0.5-1mg/kg q24h"');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_059', '两性霉素B', 'Amphotericin B', '抗真菌药', '["全身性真菌感染"]', '["严重肾功能不全(普通剂型)"]', '["肾毒性(普通剂型)", "输液反应", "低钾血症"]', '"犬：普通剂型0.25-0.5mg/kg IV 隔日；脂质体剂型1-3mg/kg IV 每周2-3次"');
INSERT INTO drugs (id, name_zh, name_en, drug_class, indications, contraindications, side_effects, species_dosing) VALUES ('drug_060', '伊曲康唑', 'Itraconazole', '抗真菌药', '["皮肤真菌病", "全身性真菌感染"]', '["严重肝病", "妊娠"]', '["肝毒性", "食欲下降", "呕吐"]', '"犬：5-10mg/kg q24h；猫：5-10mg/kg q24h（口服液）"');
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_001', '全血细胞计数（CBC）', '血液学', '犬RBC: 5.5-8.5×10⁶/μL, WBC: 6-17×10³/μL, PLT: 200-500×10³/μL | 猫RBC: 5.0-10.0×10⁶/μL, WBC: 5.5-19.5×10³/μL, PLT: 300-700×10³/μL', '贫血（RBC↓）、感染/炎症（WBC↑↓）、免疫介导性疾病、血小板减少症（PLT↓）。白细胞分类计数可区分细菌感染（中性粒↑）与病毒感染（淋巴↑/↓）', 80, 15);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_002', '血清生化全套', '生化', 'ALT犬:10-125 U/L,猫:12-130 U/L | ALP犬:23-212 U/L,猫:14-111 U/L | BUN犬:7-27 mg/dL,猫:10-30 mg/dL | CREA犬:0.5-1.8 mg/dL,猫:0.8-2.4 mg/dL | GLU犬:74-143 mg/dL,猫:74-159 mg/dL | TP犬:5.0-7.3 g/dL,猫:5.7-8.9 g/dL | ALB犬:2.3-4.0 g/dL,猫:2.1-3.3 g/dL', 'ALT/ALP评估肝功能；BUN/CREA评估肾功能（肾小球滤过率）；GLU筛查糖尿病/低血糖；TP/ALB评估营养/肝合成/渗出性丢失；电解质（K/Na/Cl）评估内分泌/肾/胃肠疾病', 200, 30);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_003', '尿液分析（UA）', '尿液', '犬尿比重:1.015-1.045 | 猫尿比重:1.035-1.060 | pH:5.5-7.5 | 蛋白:阴性~微量 | 糖:阴性 | 沉渣:偶见上皮细胞', '尿比重低+氮质血症=肾功能不全；糖尿+高血糖=糖尿病；脓尿+菌尿=尿路感染；管型=肾实质损伤；结晶=结石风险', 60, 20);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_004', '甲状腺素（T4）', '内分泌', '犬总T4:1.0-4.0 μg/dL | 猫总T4:0.8-4.0 μg/dL', '猫T4>4.0 μg/dL高度提示甲亢（老年猫最常见内分泌病）；犬T4降低提示甲亢（罕见）或甲状腺功能减退。确诊甲亢可加测fT4（游离T4）', 150, 60);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_005', '胰腺脂肪酶免疫反应性（fPLI/cPLI）', '生化', '犬cPLI:≤200 μg/L（正常）, >400 μg/L高度提示胰腺炎 | 猫fPLI:≤3.5 μg/L（正常）, >5.4 μg/L提示胰腺炎', '犬cPLI>400 μg/L对胰腺炎敏感性82%、特异性95%；猫fPLI>5.4 μg/L提示胰腺炎。需结合临床表现和影像学。慢性轻度升高可见于CKD/IBD', 250, 120);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_006', '胸部X线摄影', '影像学', '正常：心脏轮廓清晰，肺野透亮度正常，气管居中，横膈位置正常（犬：后缘约T11-13）', '心影增大=心肌病/心包积液；肺间质/肺泡浸润=肺炎/肺水肿；气管狭窄=气管塌陷；气胸=肺野透亮度增加+肺回缩；纵隔移位=占位性病变', 150, 30);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_007', '腹部超声', '影像学', '正常：肝脏回声均匀，肾脏皮髓质分界清晰，膀胱壁光滑，胰腺回声均匀，胃肠道壁层次清晰', '肾脏缩小+被膜不平=CKD；肾脏增大+回声增强=AKI/淋巴瘤；胆囊淤胆=胆管阻塞；胰腺增大+周围脂肪回声增强=胰腺炎；游离液体=腹水/出血；异物=强回声+声影', 300, 45);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_008', '超声心动图', '影像学', '犬LA/Ao<1.6（正常左房大小）| IVSd<0.6 cm（室间隔厚度）| LVIDd（左室舒张内径）因体重而异 | FS%正常:25-45%', '左房扩大（LA/Ao>1.6）=MMVD/DCM；室壁增厚（IVSd>0.6猫）=HCM；左室扩张+收缩力↓=DCM；瓣膜增厚/脱垂=MMVD；心包液暗区=心包积液', 400, 45);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_009', '血压测量', '其他', '犬收缩压:110-160 mmHg | 猫收缩压:120-170 mmHg', '高血压（犬>160,猫>170）=继发于CKD/甲亢（猫）/嗜铬细胞瘤/原发性；低血压（<90）=休克/脱水/心律失常。猫白大衣效应显著，需安静环境下多次测量', 50, 15);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_010', '血气分析', '生化', 'pH:7.35-7.45 | HCO₃⁻:18-24 mEq/L（犬）,16-24 mEq/L（猫）| pCO₂:35-45 mmHg | Na:140-155 mEq/L | K:3.5-5.5 mEq/L', '代谢性酸中毒（HCO₃⁻↓）=DKA/肾衰/乙二醇中毒；代谢性碱中毒（HCO₃⁻↑）=呕吐/利尿剂；呼吸性酸中毒（pCO₂↑）=通气不足；低钾=呕吐/利尿/无尿期后', 150, 10);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_011', 'ACTH刺激试验', '内分泌', '犬基础皮质醇:1-5 μg/dL,刺激后:5-20 μg/dL | 猫基础皮质醇:0.5-5 μg/dL,刺激后:5-15 μg/dL', '刺激后皮质醇>20 μg/dL=库欣综合征（垂体依赖或肾上腺瘤）；刺激后<2 μg/dL= Addison病（肾上腺皮质功能减退）。需结合临床症状和电解质（Na/K比）', 300, 120);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_012', '犬细小病毒抗原检测（SNAP）', '微生物', '阴性=正常', '阳性=CPV-2感染。假阴性可见于感染早期（排毒量少）或疫苗接种后近期（疫苗病毒干扰）。需结合临床表现（出血性肠炎+白细胞↓↓）综合判断', 100, 15);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_013', '猫泛白细胞减少病毒抗原检测（SNAP）', '微生物', '阴性=正常', '阳性=FPV感染。幼猫未免疫+出血性肠炎+泛白细胞减少高度提示。需与犬细小鉴别（FPV不感染犬）', 100, 15);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_014', '凝血功能检查（PT/APTT）', '血液学', 'PT:5-10秒 | APTT:10-18秒（犬）；10-20秒（猫）', 'PT延长=外源性凝血途径障碍（肝病/维生素K缺乏/灭鼠药中毒）；APTT延长=内源性途径障碍（DIC/血友病）；两者均延长=共同途径障碍/DIC/严重肝病', 120, 20);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_015', '尿液培养+药敏', '微生物', '阴性=正常 | >10⁵ CFU/mL=有意义菌尿', '确诊尿路感染的金标准。菌落计数>10⁵ CFU/mL+脓尿=确诊UTI。药敏结果指导抗生素选择。注意采样方法（膀胱穿刺最可靠）', 200, 2880);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_016', '腹腔穿刺液分析', '其他', '正常：少量清亮淡黄色液体，蛋白<2.5 g/dL,细胞数<5000/μL', '渗出液（蛋白>2.5,细胞>5000）=FIP/感染/肿瘤；漏出液（蛋白<2.5,细胞<1000）=低白蛋白/门脉高压；血性=创伤/肿瘤/凝血障碍；乳糜液=淋巴管破裂', 150, 30);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_017', '阴道细胞学/开放子宫蓄脓诊断组合', '其他', '超声：子宫直径<1 cm（正常绝经后）| 无宫内积液', '超声见子宫扩张（直径>1-2 cm）+宫内积液+临床症状（多饮多尿/呕吐/外阴分泌物）=子宫蓄脓。需与妊娠鉴别（可见胎囊/胎心）', 300, 30);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_018', '血常规涂片镜检', '血液学', '正常：成熟中性粒细胞为主，偶见杆状核（<10%），无原始细胞', '核左移（杆状粒↑）=严重感染；中毒性变化=严重炎症/败血症；原始细胞=白血病；棘红细胞=脾功能异常；海因茨小体=氧化损伤（猫：洋葱/对乙酰氨基酚中毒）', 50, 20);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_019', '腹部X线平片', '影像学', '正常：胃肠道内适量气体，无扩张肠袢，肾脏轮廓可见（右肾T13-L1，左肾L2-4），膀胱充盈', '小肠扩张（直径>肋骨宽度或>12mm猫）=梗阻；线性异物=皱褶样肠管；异物=高密度影；胃扩张=GDV（幽门右移+胃分隔征）；输尿管结石=高密度影', 120, 20);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_020', 'FIP抗体/冠状病毒抗体滴度', '微生物', '阴性或低滴度（<1:100）=正常范围', '高滴度（≥1:1600）+临床表现（发热/腹水/眼部病变/神经症状）支持FIP诊断，但非确诊。猫群中普遍阳性（FCoV携带），需结合腹腔液分析（渗出液+高球蛋白）综合判断', 200, 1440);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_021', '心丝虫抗原检测', '微生物', '阴性=正常', '阳性=犬心丝虫病确诊（检测成虫体壁抗原）。Knott试验可查微丝蚴。需结合影像学（肺动脉扩张）综合评估感染严重度', 150, 60);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_022', '皮肤细胞学', '细胞学', '正常：无细菌/少量角化细胞', '脓皮症：中性粒细胞+球菌（葡萄球菌）或杆菌。酵母菌感染：马拉色菌（花生形）。需与真菌培养鉴别', 80, 30);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_023', '淋巴结细针穿刺', '细胞学', '正常：小淋巴细胞为主，可见少量中淋巴细胞', '淋巴瘤：单一形态的大淋巴细胞大量增生，核质比增大。需与反应性增生鉴别（混合细胞群）。确诊后需分期（血常规/生化/超声/骨髓）', 120, 60);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_024', '关节液分析', '细胞学', '正常：WBC<1.5×10³/μL，以单核细胞为主，黏稠度高', '炎症性（WBC>5×10³/μL，中性粒为主）=感染性或免疫介导性。需做细菌培养排除感染。IMPA：炎症性+无细菌。感染性关节炎：炎症性+细菌培养阳性', 100, 30);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_025', '超声心动图', '影像学', '正常：LVIDd犬<55mm，FS% 25-45%，LA/Ao<1.5', 'DCM：LVIDd↑+FS%↓。HCM：室壁增厚（>6mm）+左房扩大。心包积液：心包腔内液暗区。动脉血栓：左心耳内回声团', 300, 45);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_026', 'MRI（磁共振成像）', '影像学', '正常：脑实质信号均匀，无占位性病变', '癫痫：排除结构性病变（肿瘤/脑炎/脑积水）。神经定位：脊髓压迫/椎间盘突出。软组织分辨率优于CT', 1500, 1440);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_027', '眼压测量', '眼科检查', '犬：15-25 mmHg；猫：15-27 mmHg', '>25mmHg提示青光眼；<10mmHg提示葡萄膜炎或眼球萎缩', 80, 0);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_028', '荧光素染色', '眼科检查', '阴性（无荧光素着染）', '阳性（绿色荧光着染）提示角膜上皮缺损/溃疡', 50, 0);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_029', '脑脊液分析', '神经系统检查', '犬：蛋白<30mg/dL，细胞<5个/μL；猫：蛋白<25mg/dL', '细胞数升高提示炎症或感染；蛋白升高提示血脑屏障破坏', 300, 1440);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_030', '抗核抗体检测', '免疫学检查', '阴性或滴度<1:40', '阳性（滴度≥1:160有临床意义）提示可能为SLE或其他自身免疫病', 150, 2880);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_031', '细针抽吸细胞学', '细胞学检查', '因组织类型而异', '可区分炎症与肿瘤，但常不能确定肿瘤类型和分级', 120, 1440);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_032', '凝血功能检测', '血液学检查', '犬PT：11-14s；犬aPTT：90-120s', 'PT/aPTT延长提示凝血因子缺乏或抗凝物质增多；D-二聚体升高提示纤溶亢进/DIC', 200, 60);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_033', 'Coombs试验', '免疫学检查', '阴性', '阳性提示自身抗体或补体结合于红细胞表面，支持IMHA诊断', 120, 1440);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_034', '甲状腺功能检测', '内分泌检查', '犬TT4：15-50nmol/L；猫TT4：10-50nmol/L', 'TT4降低+TSH升高=甲减；TT4升高=甲亢（猫）', 180, 1440);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_035', '尿蛋白/肌酐比', '尿液检查', '犬<0.5；猫<0.4', '0.5-2.0（犬）为蛋白尿；>2.0为显著蛋白尿，提示肾小球疾病', 80, 60);
INSERT INTO diagnostic_tests (id, name_zh, category, reference_ranges, interpretation, cost_estimate, turnaround_time) VALUES ('test_036', '血压测量', '心血管检查', '犬：收缩压110-160mmHg；猫：收缩压120-170mmHg', '>160mmHg（犬）或>170mmHg（猫）提示高血压；<90mmHg提示低血压', 50, 0);
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_001', 'drug_001', 'first', '犬', '阿莫西林-克拉维酸是犬细菌性肺炎的一线抗生素');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_001', 'drug_003', 'adjunctive', '犬', '严重呼吸困难时辅助利尿，但需排除心衰');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_001', 'drug_018', 'first', '猫', '猫吸入性肺炎可用阿莫西林');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_002', 'drug_003', 'first', '犬', '呋塞米是心衰一线利尿剂，急性肺水肿可IV');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_002', 'drug_006', 'first', '犬', '匹莫苯丹改善心室收缩功能，与呋塞米联用');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_002', 'drug_015', 'second', '犬', '合并房颤时用于心室率控制，需监测血药浓度');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_003', 'drug_004', 'first', '猫', '泼尼松龙是猫哮喘一线抗炎药物，猫需较高剂量');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_003', 'drug_023', 'adjunctive', '猫', '急性发作时辅助镇静/支气管扩张');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_004', 'drug_004', 'adjunctive', '犬', '泼尼松龙减轻气管炎症/水肿，短期使用');
