INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_031', 'drug_042', 'first', '犬', '苯巴比妥是犬特发性癫痫一线抗癫痫药，需监测血药浓度（目标15-40 μg/mL）');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_031', 'drug_043', 'second', '犬', '溴化钾用于苯巴比妥单药控制不佳时联合用药，起效慢（需3-6月达稳态）');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_031', 'drug_032', 'adjunctive', '犬', '加巴喷丁辅助抗癫痫，也可用于癫痫持续状态的急性期辅助');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_032', 'drug_004', 'first', '犬', '泼尼松龙2 mg/kg诱导缓解，4周后逐渐减量至最低有效剂量');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_032', 'drug_044', 'second', '犬', '硫唑嘌呤作为激素节约剂，与泼尼松龙联用减少激素用量');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_033', 'drug_004', 'first', '犬', '大剂量泼尼松龙（2-4 mg/kg）免疫抑制是IMHA核心治疗');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_033', 'drug_044', 'second', '犬', '硫唑嘌呤用于激素效果不佳或需减少激素用量时');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_033', 'drug_003', 'adjunctive', '犬', '严重贫血（HCT<15%）时输血支持，同时利尿防液体过负荷');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_034', 'drug_045', 'first', '犬', '环磷酰胺是CHOP方案核心组分，每周给药');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_034', 'drug_046', 'first', '犬', '长春新碱是CHOP方案核心组分，每周IV给药，注意渗漏可致组织坏死');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_034', 'drug_047', 'first', '犬', '多柔比星是CHOP方案核心组分，每3周IV给药，累积心脏毒性上限240 mg/m²');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_034', 'drug_004', 'first', '犬', '泼尼松龙是CHOP方案组成部分，单用也可短期缓解');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_035', 'drug_012', 'first', '犬', '美洛昔康用于术前术后镇痛和慢性骨关节炎管理');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_035', 'drug_011', 'adjunctive', '犬', '曲马多用于术后急性期辅助镇痛');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_036', 'drug_048', 'first', '犬', '美拉索明（Immiticide）杀成虫，3次IM注射方案，严格限制运动防肺栓塞');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_036', 'drug_049', 'first', '犬', '伊维菌素每月一次预防用药是最佳策略，柯利犬MDR1突变慎用（预防量安全）');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_037', 'drug_001', 'first', '犬', '阿莫西林-克拉维酸是浅表性脓皮症一线抗生素，疗程3-4周');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_037', 'drug_002', 'second', '犬', '恩诺沙星用于深层感染或一线无效时，注意幼犬软骨毒性');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_038', 'drug_055', 'adjunctive', '犬', '贝那普利控制糖尿病相关白内障进展（辅助）');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_039', 'drug_003', 'adjunctive', '犬', '甘露醇IV快速降眼压（急性发作急救），但需注意脱水');
