INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_044', 'drug_046', 'first', '犬', '多柔比星为基础的化疗方案，术后辅助延长生存期');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_045', 'drug_004', 'second', '犬', '泼尼松龙短期控制急性发作，长期使用副作用大');
