INSERT INTO disease_diagnostic (disease_id,test_id,purpose,evidence_level,species,expected_result) VALUES ('dis_001', 'test_006', 'confirming', 'supportive', '犬', '肺间质/肺泡浸润影，肺门周围为主');
INSERT INTO disease_diagnostic (disease_id,test_id,purpose,evidence_level,species,expected_result) VALUES ('dis_001', 'test_001', 'screening', 'supportive', '犬', '白细胞升高（细菌感染时中性粒↑）');
INSERT INTO disease_diagnostic (disease_id,test_id,purpose,evidence_level,species,expected_result) VALUES ('dis_001', 'test_010', 'monitoring', 'supportive', '犬', '低氧血症，严重时呼吸性酸中毒');
INSERT INTO disease_diagnostic (disease_id,test_id,purpose,evidence_level,species,expected_result) VALUES ('dis_002', 'test_008', 'confirming', 'gold_standard', '犬', '左房/左室扩大，EF可能降低，瓣膜反流（MMVD）');
INSERT INTO disease_diagnostic (disease_id,test_id,purpose,evidence_level,species,expected_result) VALUES ('dis_002', 'test_006', 'confirming', 'supportive', '犬', '心影增大，肺静脉充血，肺水肿（肺泡浸润）');
